const items = $input.all();
const allItems = [];
let ok = 0;
for (const item of items) {
  const data = item.json.data;
  const body = typeof data === 'string' ? data : (item.json.body || '');
  const src = item.json.src || 'unknown';
  const type = item.json.type || 'rss';
  if (!body) continue;
  ok++;
  if (type === 'json') {
    let parsed;
    try { parsed = JSON.parse(body); } catch (e) { continue; }
    const children = parsed && parsed.data && parsed.data.children;
    if (!Array.isArray(children)) continue;
    for (const c of children.slice(0, 5)) {
      if (c && c.data && c.data.title) {
        allItems.push({ title: c.data.title, source: src });
      }
    }
  } else {
    const re = /<item[\s\S]*?<title[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/title>[\s\S]*?<\/item>/gi;
    let m, c = 0;
    while ((m = re.exec(body)) !== null && c < 8) {
      const t = (m[1] || '').trim();
      if (t) allItems.push({ title: t, source: src });
      c++;
    }
  }
}
if (!allItems.length) return [{ json: { skip: true, total: 0, feeds_ok: ok, feeds_total: items.length } }];
return allItems.map(i => ({ json: i }));

const critical = ['rate cut','rate hike','rate decision','recession','military strike','nuclear','invasion','declares war','debt default'];
const high = ['interest rate decision','federal reserve statement','fomc statement','ecb rate','bank of japan rate','inflation data','cpi report','sanctions package','new tariff','trade war escalat','opec cut','opec production cut','embargo'];
const medium = ['gold price','oil price','crude oil price','natural gas price','copper price','gdp growth','gdp data','unemployment rate','nonfarm payroll','earnings beat','earnings miss','bitcoin price','crypto market'];

function classify(title) {
  const t = title.toLowerCase();
  for (const p of critical) if (t.includes(p)) return { impact: 'critical', type: getType(p), assets: getAssets(p) };
  for (const p of high) if (t.includes(p)) return { impact: 'high', type: getType(p), assets: getAssets(p) };
  for (const p of medium) if (t.includes(p)) return { impact: 'medium', type: getType(p), assets: getAssets(p) };
  return null;
}
function getType(p) {
  if (/rate|fed|fomc|ecb|boj|inflation|cpi/.test(p)) return 'policy_change';
  if (/sanction|embargo/.test(p)) return 'sanctions';
  if (/tariff|trade war/.test(p)) return 'trade_war';
  if (/military|nuclear|invasion|war/.test(p)) return 'conflict';
  if (/recession|default|gdp|unemployment|nonfarm/.test(p)) return 'macro';
  if (/opec|gold|oil|crude|gas|copper/.test(p)) return 'commodity';
  if (/bitcoin|crypto/.test(p)) return 'crypto';
  if (/earnings/.test(p)) return 'corporate';
  return 'general';
}
function getAssets(p) {
  const m = {'rate cut':['GOLD','TLT','SPY'],'rate hike':['GOLD','TLT','SPY'],'rate decision':['GOLD','TLT','SPY'],'recession':['SPY','GOLD','TLT'],'military strike':['GOLD','OIL'],'nuclear':['GOLD','OIL','USD'],'invasion':['GOLD','OIL'],'declares war':['GOLD','OIL'],'debt default':['GOLD','TLT','SPY'],'interest rate decision':['GOLD','TLT','USD'],'federal reserve statement':['GOLD','SPY'],'fomc statement':['GOLD','SPY','TLT'],'ecb rate':['EUR','GOLD'],'bank of japan rate':['JPY','GOLD'],'inflation data':['GOLD','TLT'],'cpi report':['GOLD','SPY'],'sanctions package':['GOLD','OIL'],'new tariff':['SPY','COPPER'],'trade war escalat':['SPY','COPPER','GOLD'],'opec cut':['OIL'],'opec production cut':['OIL'],'embargo':['OIL','GOLD'],'gold price':['GOLD','SILVER'],'oil price':['OIL'],'crude oil price':['OIL'],'natural gas price':['NATGAS'],'copper price':['COPPER'],'gdp growth':['SPY'],'gdp data':['SPY'],'unemployment rate':['SPY','GOLD'],'nonfarm payroll':['SPY','GOLD'],'earnings beat':['SPY'],'earnings miss':['SPY'],'bitcoin price':['BTC'],'crypto market':['BTC','ETH']};
  return m[p] || [];
}

const items = $input.all();
const results = [];
for (const item of items) {
  if (item.json.skip) return [item];
  const cls = classify(item.json.title || '');
  if (!cls) continue;
  results.push({ json: { event_type: cls.type, description: item.json.title, sentiment_score: 0, affected_assets: cls.assets, source: item.json.source || 'rss_news', impact_level: cls.impact } });
}
if (!results.length) return [{ json: { skip: true, total: items.length } }];
return results;

const recentRows = $('Get Recent 24h').all();
const existing = new Set(recentRows.map(r => (r.json.d || '').toLowerCase().trim()));
const classified = $('Classify').all();
const newItems = [];
for (const item of classified) {
  if (item.json.skip) continue;
  const prefix = (item.json.description || '').substring(0, 100).toLowerCase().trim();
  if (!existing.has(prefix)) {
    newItems.push(item);
    existing.add(prefix);
  }
}
if (!newItems.length) return [{ json: { skip: true, new_count: 0 } }];
return newItems;

const items = $input.all();
const critical = items.filter(i => i.json.impact_level === 'critical').slice(0, 3);
if (!critical.length) return [];
const lines = critical.map(i => {
  const e = i.json;
  const assets = (e.affected_assets || []).join(', ');
  return '\ud83d\udea8 *' + (e.event_type || 'NEWS').toUpperCase() + '* [' + e.source + ']\n' + e.description + '\nAssets: ' + assets;
}).join('\n\n');
return [{ json: { message: '\ud83d\udcf0 *Critical News*\n\n' + lines } }];

